const result = $input.first().json;

if (!result || result.valid !== true) {
  throw new Error('Invalid request signature');
}

const authHeader = $('Receive Health Request').first().json.headers.authorization ?? '';
const token = authHeader.replace('Bearer ', '').trim();

return [{ json: { hmac_valid: true, token } }];

const session = $input.first().json;
const requestedSlug = $('Receive Health Request').first().json.query.client_id;

if (!session || !session.user_id) {
  throw new Error('Invalid or expired token');
}

if (!session.user_active) {
  throw new Error('User account is inactive');
}

if (!session.client_active) {
  throw new Error('Client account is inactive');
}

const allowedRoles = ['staff', 'admin', 'owner'];
const hasClientAccess = allowedRoles.includes(session.role) && session.slug === requestedSlug;
const isCaiacStaff = session.is_caiac_staff === true;

if (!hasClientAccess && !isCaiacStaff) {
  throw new Error('Insufficient permissions');
}

return [{
  json: {
    user_id: session.user_id,
    role: session.role,
    client_slug: requestedSlug,
    is_caiac_staff: isCaiacStaff,
    name: session.name,
    email: session.email
  }
}];

const collection = $('Get Collection Info').first().json;
const docCount = $('Count Document Points').first().json;
const chatCount = $('Count Chat History Points').first().json;
const knowledgeCount = $('Count Knowledge Points').first().json;

return [{
  json: {
    status: collection.result?.status ?? 'unknown',
    vector_size: collection.result?.config?.params?.vectors?.size ?? null,
    document_points: docCount.result?.count ?? 0,
    chat_history_points: chatCount.result?.count ?? 0,
    knowledge_points: knowledgeCount.result?.count ?? 0,
    embed_model: 'bge-m3:latest'
  }
}];
